import{_ as t,o as a,c as r,a3 as n}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"59. Aboriginal Healthcare Worker Traineeship Mental Health","description":"","frontmatter":{"title":"59. Aboriginal Healthcare Worker Traineeship Mental Health","eba":"Mental Health Services 2024-2028","topics":["preliminary"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/staffing/59-aboriginal-healthcare-worker-traineeship-mental-health.md","filePath":"ebas/mental-health/common-terms/staffing/59-aboriginal-healthcare-worker-traineeship-mental-health.md"}'),i={name:"ebas/mental-health/common-terms/staffing/59-aboriginal-healthcare-worker-traineeship-mental-health.md"};function o(s,e,l,h,p,c){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="_59-aboriginal-healthcare-worker-traineeship-mental-health" tabindex="-1">59. Aboriginal Healthcare Worker Traineeship Mental Health <a class="header-anchor" href="#_59-aboriginal-healthcare-worker-traineeship-mental-health" aria-label="Permalink to &quot;59. Aboriginal Healthcare Worker Traineeship Mental Health&quot;">​</a></h1><p><strong>59.1</strong> Application</p><p><strong>(a)</strong> The Aboriginal Healthcare Worker (Mental Health) Traineeship Program is a Victorian State Government initiative designed to increase the Aboriginal workforce within the public mental health sector whilst increasing culturally safe and inclusive mental health care for Aboriginal people.</p><p><strong>(b)</strong> This clause applies only to the employment of an Aboriginal Health Worker Traineeship (Mental Health).</p><p><strong>(c)</strong> Anyone who is initially engaged pursuant to this Traineeship Program will be classified as Aboriginal Health Worker Trainee for the duration of their Traineeship.</p><p><strong>59.2</strong> Definitions</p><p><strong>(a)</strong> Approved Training means the Degree of Bachelor of Health Sciences (Mental Health) at Charles Sturt University (Traineeship).</p><p><strong>(b)</strong> Trainee means Aboriginal Health Worker (Mental Health) Trainee.</p><p><strong>(c)</strong> Traineeship means a Trainee enrolled in Degree of Bachelor of Health Science (Mental Health) at Charles Sturt University in Wagga Wagga, New South Wales.</p><p><strong>59.3</strong> Conditions</p><p><strong>(a)</strong> The Trainee must be enrolled in the Approved Training.</p><p><strong>(b)</strong> The Trainee must be of Aboriginal and/or Torres Strait Islander background.</p><p><strong>(c)</strong> The Trainee will on a fulltime maximum term contract.</p><p><strong>(d)</strong> The Trainee will be expected to maintain satisfactory course progress and to complete the course in three years.</p><p><strong>(e)</strong> The Employer will meet the student contribution costs of the Approved Training and release the Trainee from duty to attend campus or placements as required.</p><p><strong>(f)</strong> The Employer will ensure that there is appropriate support to ensure that the Trainee are able to undertake the study modules.</p><p><strong>(g)</strong> The Trainee must be an undergraduate student and will work under the supervision of a Health Practitioner. The Employer will ensure that the Trainee will have access to this supervision.</p><p><strong>(h)</strong> Allowances will be paid in accordance with Section 3 – Health Professionals.</p><p><strong>(i)</strong> Upon successful completion of the Traineeship, the Trainee will be offered ongoing employment and paid as per the Grade 2 Health Professional table in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>.</p><p><strong>(j)</strong> Where the employment of Aboriginal Health Worker Traineeship (Mental Health) by an Employer is continued after the completion of the traineeship period, such employment period will be counted as service for the purposes of this Agreement or any other legislative entitlement.</p><p><strong>59.4</strong> Duties</p><p><strong>(a)</strong> Participate in the development and implementation of mental health services to promote the social and emotional well-being of aboriginal people and the wider community.</p><p><strong>(b)</strong> Learn about, observe and develop skills to provide responsive and culturally appropriate mental health services to consumers across the lifespan.</p><p><strong>(c)</strong> Provide information, consistent with the academic curriculum, about healthy lifestyles and support changes in lifestyle and self-care strategies (e.g. nutrition, exercise, smoking, alcohol and stress).</p><p><strong>(d)</strong> Actively contribute to multidisciplinary discussions and planning.</p><p><strong>(e)</strong> Work collaboratively with families, communities, relevant agencies, health service staff and relevant support services to ensure consumer needs are met.</p><p><strong>(f)</strong> Working alongside Health Practitioners, participate in the referral, assessment, review and discharge processes.</p><p><strong>(g)</strong> Be actively involved in the provision of health promotion and community development programs.</p><p><strong>(h)</strong> Advocate and advise on behalf of Aboriginal and Torres Strait Islander consumers at case discussions and legal hearings (as appropriate) to ensure that the needs of the consumers are expressed.</p><p><strong>(i)</strong> Undertake documentation of all consumer involvement in the prescribed notes, ensuring that these are countersigned by the supervising Health Practitioner.</p><p><strong>(j)</strong> Report within a timely manner, any identified issues of concern.</p>',31)])])}const d=t(i,[["render",o]]);export{m as __pageData,d as default};
